15	// UsageReportOptions configures FizeauService.UsageReport.
16	type UsageReportOptions struct {
17		// Since limits the report window. Supported values include "today", "7d",
18		// "30d", a date range "YYYY-MM-DD..YYYY-MM-DD", or a single start date.
19		// Empty means no window filter (all sessions).
20		Since string
21		// Now is the reference time for relative windows. Zero means time.Now().
22		Now time.Time
23	}
24	
25	// UsageReport is the public, service-owned aggregation over historical session
26	// logs. CLI subcommands consume this projection rather than re-reading the
27	// session-log JSONL schema directly.
28	//
29	// RoutingQuality (ADR-006 §5) summarizes how often auto-routing produced an
30	// acceptable decision over the report window. It is intentionally distinct
31	// from the per-(provider, model) provider-reliability rate carried on each
32	// UsageReportRow (Row.SuccessRate); the two metrics measure different
33	// things and should be presented as separate numbers in operator UIs.
34	type UsageReport struct {
35		Window         *UsageReportWindow    `json:"window,omitempty"`
36		Rows           []UsageReportRow      `json:"rows"`
37		Totals         UsageReportRow        `json:"totals"`
38		RoutingQuality RoutingQualityMetrics `json:"routing_quality"`
39	}
40	
41	// UsageReportWindow describes the active reporting window.
42	type UsageReportWindow struct {
43		Start time.Time `json:"start"`
44		End   time.Time `json:"end"`
45	}
46	
47	// UsageReportRow aggregates usage for one provider/model pair.
48	type UsageReportRow struct {
49		Provider            string   `json:"provider"`
50		Model               string   `json:"model"`
51		Sessions            int      `json:"sessions"`
52		SuccessSessions     int      `json:"success_sessions"`
53		FailedSessions      int      `json:"failed_sessions"`
54		InputTokens         int      `json:"input_tokens"`
55		OutputTokens        int      `json:"output_tokens"`
56		TotalTokens         int      `json:"total_tokens"`
57		DurationMs          int64    `json:"duration_ms"`
58		KnownCostUSD        *float64 `json:"known_cost_usd"`
59		UnknownCostSessions int      `json:"unknown_cost_sessions"`
60		CacheReadTokens     int      `json:"cache_read_tokens"`
61		CacheWriteTokens    int      `json:"cache_write_tokens"`
62	}
63	
64	// SuccessRate returns the fraction of sessions that succeeded (0 if no sessions).
65	func (r UsageReportRow) SuccessRate() float64 {
66		if r.Sessions == 0 {
67			return 0
68		}
69		return float64(r.SuccessSessions) / float64(r.Sessions)
70	}
71	
72	// CostPerSuccess returns the known cost divided by successful sessions, or nil
73	// if there are no successes or cost is unknown.
74	func (r UsageReportRow) CostPerSuccess() *float64 {
75		if r.SuccessSessions == 0 || r.KnownCostUSD == nil {
76			return nil
77		}
78		v := *r.KnownCostUSD / float64(r.SuccessSessions)
79		return &v
80	}
81	
82	// InputTokensPerSecond returns the average input-token throughput.
83	func (r UsageReportRow) InputTokensPerSecond() float64 {
84		if r.DurationMs <= 0 {
85			return 0
86		}
87		return float64(r.InputTokens) / (float64(r.DurationMs) / 1000)
88	}
89	
90	// OutputTokensPerSecond returns the average output-token throughput.
91	func (r UsageReportRow) OutputTokensPerSecond() float64 {
92		if r.DurationMs <= 0 {
93			return 0
94		}
95		return float64(r.OutputTokens) / (float64(r.DurationMs) / 1000)
96	}
97	
98	// CacheHitRate returns the fraction of input tokens served from cache (0..1).
99	func (r UsageReportRow) CacheHitRate() float64 {
100		total := r.InputTokens + r.CacheReadTokens + r.CacheWriteTokens
101		if total == 0 {
102			return 0
103		}
104		return float64(r.CacheReadTokens) / float64(total)
105	}
106	
107	// SessionLogEntry describes one historical session log file projected from the
108	// service-owned session-log directory. Consumers display these without reading
109	// directory contents directly.
110	type SessionLogEntry struct {
111		SessionID string    `json:"session_id"`
112		ModTime   time.Time `json:"mod_time"`
113		Size      int64     `json:"size"`
114	}
115	
116	// ValidateUsageSince returns nil when spec is a usage window value accepted by
117	// UsageReport. CLI subcommands call this to surface exit-code-2 validation
118	// errors before invoking the service.
119	func ValidateUsageSince(spec string) error {
120		_, err := session.ParseUsageWindow(strings.TrimSpace(spec), time.Now().UTC())
121		return err
122	}
123	
124	// UsageReport aggregates token, cost, and reliability totals across the
125	// service-owned session-log directory.
126	//
127	// RoutingQuality is sourced from persisted session logs, not the in-memory
128	// ring (ADR-006 §5): UsageReport's --since window can extend across
129	// restarts and beyond the ring's bounded retention, so the authoritative
130	// data source has to be the on-disk session-log corpus that already
131	// carries override and rejected_override events. When no log directory is
132	// configured, the in-memory ring is used as a best-effort fallback so
133	// in-process callers still see live routing-quality numbers.
134	func (s *service) UsageReport(ctx context.Context, opts UsageReportOptions) (*UsageReport, error) {
135		if err := ctx.Err(); err != nil {
136			return nil, err
137		}
138		now := opts.Now
139		if now.IsZero() {
140			now = time.Now().UTC()
141		}
142		logDir := s.publicSessionLogDir()
143		if logDir == "" {
144			// AC bug-fix: even without a log directory, surface the
145			// in-memory ring's live routing-quality so the field is never
146			// silently dropped.
147			report := &UsageReport{}
148			report.RoutingQuality = s.routingQualityFromRing(nil)
149			return report, nil
150		}
151		internal, err := serviceimpl.UsageReport(ctx, logDir, session.UsageOptions{
152			Since: opts.Since,
153			Now:   now,
154		})
155		if err != nil {
156			return nil, err
157		}
158		report := convertUsageReport(internal)
159		rq, err := s.routingQualityFromSessionLogs(logDir, report.Window)
160		if err != nil {
161			return nil, err
162		}
163		report.RoutingQuality = rq
164		return report, nil
165	}
166	
167	// routingQualityFromSessionLogs is the windowed reader UsageReport calls
168	// to rebuild RoutingQualityMetrics from persisted override events. The
169	// session-log corpus is authoritative because it survives restarts and
170	// supports arbitrary --since windows; the in-memory ring is bounded and
171	// recent-only.
172	func (s *service) routingQualityFromSessionLogs(logDir string, window *UsageReportWindow) (RoutingQualityMetrics, error) {
173		scanWindow := convertUsageWindow(window)
174		scan, err := session.ScanRoutingQuality(logDir, scanWindow)
175		if err != nil {
176			return RoutingQualityMetrics{}, err
177		}
178		overrides := decodeRoutingQualityOverrides(scan.OverrideEvents)
179		return computeRoutingQualityMetrics(scan.TotalRequests, overrides), nil
180	}
181	
182	// routingQualityFromRing is the fallback path used when no session-log
183	// directory is configured: aggregate from the in-memory ring over window
184	// (nil = all records).
185	func (s *service) routingQualityFromRing(window *UsageReportWindow) RoutingQualityMetrics {
186		if s == nil || s.routingQuality == nil {
187			return RoutingQualityMetrics{}
188		}
189		var start, end time.Time
190		if window != nil {
191			start = window.Start
192			end = window.End
193		}
194		records := s.routingQuality.snapshotWindow(start, end)
195		return computeRoutingQualityMetricsFromRecords(records)
196	}
197	
198	// decodeRoutingQualityOverrides converts persisted override / rejected_override
199	// session-log events back into ServiceOverrideData payloads. Events that
200	// fail to decode are skipped — a single corrupt record must not poison the
201	// whole report.
202	func decodeRoutingQualityOverrides(events []agentcore.Event) []ServiceOverrideData {
203		if len(events) == 0 {
204			return nil
205		}
206		out := make([]ServiceOverrideData, 0, len(events))
207		for _, e := range events {
208			var payload ServiceOverrideData
209			if err := json.Unmarshal(e.Data, &payload); err != nil {
210				continue
211			}
212			out = append(out, payload)
213		}
214		return out
215	}
216	
217	func convertUsageWindow(w *UsageReportWindow) *session.UsageWindow {
218		if w == nil {
219			return nil
220		}
221		return &session.UsageWindow{Start: w.Start, End: w.End}
222	}
223	
224	// ListSessionLogs returns the session log files known to the service, sorted
225	// alphabetically by session ID.
226	func (s *service) ListSessionLogs(ctx context.Context) ([]SessionLogEntry, error) {
227		if err := ctx.Err(); err != nil {
228			return nil, err
229		}
230		logDir := s.publicSessionLogDir()
231		entries, err := serviceimpl.ListSessionLogs(ctx, logDir)
232		if err != nil {
233			return nil, err
234		}
235		out := make([]SessionLogEntry, 0, len(entries))
236		for _, entry := range entries {
237			out = append(out, SessionLogEntry{
238				SessionID: entry.SessionID,
239				ModTime:   entry.ModTime,
240				Size:      entry.Size,
241			})
242		}
243		return out, nil
244	}
245	
246	// WriteSessionLog renders every event in the named session log to w as
247	// indented JSON, one event per object. The format is service-owned; consumers
248	// do not parse it back into private session-log structs.
249	func (s *service) WriteSessionLog(ctx context.Context, sessionID string, w io.Writer) error {
250		if err := ctx.Err(); err != nil {
251			return err
252		}
253		path, err := s.sessionLogPath(sessionID)
254		if err != nil {
255			return err
256		}
257		return serviceimpl.WriteSessionLog(ctx, path, w)
258	}
259	
260	// ReplaySession renders a human-readable conversation transcript for the named
261	// session log onto w.
262	func (s *service) ReplaySession(ctx context.Context, sessionID string, w io.Writer) error {
263		if err := ctx.Err(); err != nil {
264			return err
265		}
266		path, err := s.sessionLogPath(sessionID)
267		if err != nil {
268			return err
269		}
270		return serviceimpl.ReplaySession(ctx, path, w)
271	}
272	
273	// publicSessionLogDir resolves the directory used by the public session-log
274	// projection methods. Resolution order:
275	//  1. ServiceOptions.SessionLogDir override.
276	//  2. ServiceConfig.SessionLogDir() default.
277	//
278	// Returns "" when neither source supplies a directory.
279	func (s *service) publicSessionLogDir() string {
280		return s.serviceSessionLogDir()
281	}
282	
283	func (s *service) sessionLogPath(sessionID string) (string, error) {
284		return serviceimpl.SessionLogPath(s.publicSessionLogDir(), sessionID)
285	}
286	
287	func convertUsageReport(in *session.UsageReport) *UsageReport {
288		if in == nil {
289			return &UsageReport{}
290		}
291		out := &UsageReport{
292			Rows:   make([]UsageReportRow, 0, len(in.Rows)),
293			Totals: convertUsageRow(in.Totals),
294		}
295		if in.Window != nil {
296			out.Window = &UsageReportWindow{Start: in.Window.Start, End: in.Window.End}
297		}
298		for _, row := range in.Rows {
299			out.Rows = append(out.Rows, convertUsageRow(row))
300		}
301		return out
302	}
303	
304	func convertUsageRow(in session.UsageRow) UsageReportRow {
305		row := UsageReportRow{
306			Provider:            in.Provider,
307			Model:               in.Model,
308			Sessions:            in.Sessions,
309			SuccessSessions:     in.SuccessSessions,
310			FailedSessions:      in.FailedSessions,
311			InputTokens:         in.InputTokens,
312			OutputTokens:        in.OutputTokens,
313			TotalTokens:         in.TotalTokens,
314			DurationMs:          in.DurationMs,
315			UnknownCostSessions: in.UnknownCostSessions,
316			CacheReadTokens:     in.CacheReadTokens,
317			CacheWriteTokens:    in.CacheWriteTokens,
318		}
319		if in.KnownCostUSD != nil {
320			v := *in.KnownCostUSD
321			row.KnownCostUSD = &v
322		}
323		return row
324	}
